INSERT INTO `table_finance` VALUES ('Britam Money Market Fund','Kenya\'s lowest MMF minimum at KES 500. Britam MMF is ideal for young earners starting their savings journey. Interest earned daily and reinvested automatically.','0.099',500),('Sanlam Money Market Fund','Sanlam MMF offers competitive daily yields backed by a diversified portfolio of government securities and bank deposits. Minimum KES 1,000. No lock-in period. Top-10 performing MMF in Kenya.','0.105',1000),('ICEA Lion Money Market','ICEA Lion MMF combines safety and liquidity for professionals managing working capital or emergency savings. Portfolio: 60% government securities, 40% bank placements.','0.10300000000000001',1000),('Safaricom PLC Shares','Safaricom is East Africa\'s largest company by market cap. M-Pesa ecosystem drives double-digit earnings growth. Historically pays KES 0.60-0.76 dividend per share. Buy through a licensed stockbroker.','0.12',1000),('Nabo Africa Money Market','Nabo MMF is available in KES and USD. Ideal for diaspora remittances. Daily interest compounded. KES minimum 1,000 or USD 10 equivalent.','0.10800000000000001',1000),('KCB Group Shares','KCB Group is Kenya\'s largest bank by assets. Strong regional footprint. DRC operations a growth catalyst. Dividend yield approximately 8-10%.','0.115',1000),('CIC Money Market Fund','CIC MMF is Kenya\'s most accessible money market fund. Earn daily interest on savings from KES 1,000. Backed by T-Bills, commercial paper, and bank deposits. Interest paid daily. Withdraw next business day.','0.102',1000),('Equity Group Holdings Shares','Equity Bank — one of Africa\'s most profitable banks by ROE. Pan-African presence across 7 countries. Strong dividend track record: KES 4.00 per share (FY2024). Accessible via NSE.','0.14',1000),('New Gold ETF (GLD)','New Gold ETF tracks the gold spot price in KES terms. One unit = 1/100th of a troy ounce of gold. Trades on NSE. Ideal for investors seeking a hedge against KES depreciation and inflation.','0.085',5000),('Stima Sacco Share Capital','Stima Sacco\'s share capital consistently delivers 14-16% annual dividend. Open to Kenya Power employees and the public (through BOSA and FOSA accounts). Minimum 50 shares at KES 100 each.','0.145',5000),('Old Mutual Enhanced Income','Old Mutual\'s Enhanced Income Fund invests in slightly longer-tenor government securities for a yield premium over standard MMFs. Weekly liquidity. Minimum KES 5,000.','0.114',5000),('Mwalimu National Sacco Shares','Mwalimu National Sacco — Kenya\'s largest Sacco by asset base. 13-15% annual dividends on share capital. Membership open to all TSC-registered teachers. FOSA accounts earn 4% p.a. on savings.','0.132',10000),('Cytonn High Yield Fund','Cytonn HYF invests in corporate bonds, real estate notes, and structured credit. Higher yield than T-Bill-backed MMFs, with commensurate credit risk. Minimum KES 10,000.','0.138',10000),('Harambee Sacco Deposits','Harambee FOSA fixed deposits earn 9-10% p.a. for 12-month tenors. Open to civil servants and the general public. Deposits are protected by DCS (Deposit Compensation Scheme).','0.095',10000),('91-Day Treasury Bill','Kenya 91-day T-Bill. Sold at a discount. Minimum purchase one face value unit (KES 50,000 face). Historically 13-16% p.a. equivalent. No default risk. Buy through CBK DhowCSD portal or commercial bank.','0.14800000000000002',49680),('364-Day Treasury Bill','Kenya 364-day T-Bill — highest yield in the T-Bill curve. 1-year lock-in. Minimum KES 50,000 face value. Competitive vs. bank FDs with zero credit risk.','0.156',49680),('182-Day Treasury Bill','Kenya 182-day T-Bill. Better yield than 91-day for slightly longer lock-in. Same minimum. Zero credit risk. Ideal for money not needed for 6 months.','0.152',49680),('KCB Bank Fixed Deposit','KCB 12-month FD. Negotiable rate for amounts above KES 1M. KDIC-insured. Can be used as collateral for an emergency loan at KCB.','0.09',50000),('Infrastructure Bond IFB1/2025/10','Kenya Infrastructure Bond — interest income is TAX FREE. 10-year tenor. Semi-annual coupon payments. Funds earmarked for road, energy, and water infrastructure. Highly sought after by retail investors.','0.168',50000),('Equity Bank Fixed Deposit','Equity Bank 12-month fixed deposit. KDIC-insured up to KES 500,000. Interest paid at maturity. Good for capital that must be preserved with a guaranteed return.','0.095',50000);
/*!40000 ALTER TABLE `table_finance` ENABLE KEYS */;
UNLOCK TABLES;

